<template>
    <v-navigation-drawer v-model="drawerModel" temporary app>
        <v-list>
            <v-list-item>
                <div class="d-flex justify-space-between align-center w-100">
                    <v-list-item-title class="text-h6">Filtros</v-list-item-title>
                    <v-tooltip v-bind="tooltipProps" text="Cerrar" location="bottom">
                        <template v-slot:activator="{ props }">
                            <v-btn v-bind="props" color="red" icon="mdi-close-circle-outline" variant="text"
                                size="small" @click="drawerModel = false"></v-btn>
                        </template>
                    </v-tooltip>
                </div>
            </v-list-item>
            <div class="px-4 pt-4 pb-2">
                <v-select color="indigo" v-model="selectedFilterModel" :items="filters" label="Buscar por:"
                    variant="outlined" density="compact" hide-details></v-select>
            </div>
            <div class="px-4 py-2">
                <v-switch v-model="stateModel" :label="`Estado: ${stateModel}`" false-value="Inactivos"
                    true-value="Activos" color="indigo" hide-details></v-switch>
            </div>
            <div class="px-4 py-2">
                <v-date-input color="indigo" v-model="startDateModel" label="Desde:" prepend-icon="" variant="outlined"
                    density="compact" persistent-placeholder hide-details></v-date-input>
            </div>
            <div class="px-4 py-2">
                <v-date-input color="indigo" v-model="endDateModel" label="Hasta:" prepend-icon="" variant="outlined"
                    density="compact" persistent-placeholder :error="!!dateError" :error-messages="dateError"
                    hide-details="auto"></v-date-input>
            </div>
            <v-list-item class="pt-4">
                <v-btn color="indigo" block :disabled="!!dateError" @click="emit('apply-filters')">Aplicar</v-btn>
            </v-list-item>
            <v-list-item>
                <v-btn color="indigo" block @click="clearFilters">Restablecer</v-btn>
            </v-list-item>
        </v-list>
    </v-navigation-drawer>
</template>

<script setup lang="ts">
import { computed } from 'vue'
import { useFiltersSync } from '@/composables/useModelSync';
import { useResponsiveTooltip } from '@/composables/useResponsiveTooltip';

// Props del componente
interface Props {
    modelValue: boolean;
    filters: string[];
    selectedFilter: string;
    state?: string;
    startDate?: Date | null;
    endDate?: Date | null;
}

const props = withDefaults(defineProps<Props>(), {
    state: 'Activos',
    startDate: null,
    endDate: null
});

const { tooltipProps } = useResponsiveTooltip();

// Emits del componente
const emit = defineEmits<{
    'update:modelValue': [value: boolean];
    'update:selectedFilter': [value: string];
    'update:state': [value: string];
    'update:startDate': [value: Date | null];
    'update:endDate': [value: Date | null];
    'apply-filters': [];
}>();

// Usa el composable para toda la lógica de sincronización
const {
    drawerModel,
    selectedFilterModel,
    stateModel,
    startDateModel,
    endDateModel,
    clearFilters
} = useFiltersSync(props, emit);

const dateError = computed(() => {
    if (startDateModel.value && endDateModel.value) {
        return startDateModel.value > endDateModel.value
            ? 'La fecha "Hasta" debe ser mayor o igual a "Desde"'
            : '';
    }
    return '';
});
</script>